  "get_alert_details": {
    "description": "Retrieves the core information of an AML alert, including the subject name, flagged transaction IDs, and current workflow status.",
    "parameters": {
      "type": "object",
      "properties": {
        "alert_id": {
          "type": "string",
          "description": "The unique identifier for the AML alert (e.g., 'AML-2025-X82')."
        }
      },
      "required": [
        "alert_id"
      ]
    },
    "example_output": {
      "alert_id": "AML-2025-X82",
      "subject_name": "Riverside Janitorial Services",
      "flagged_transaction_ids": [
        "TXN_001",
        "TXN_002"
      ],
      "current_status": "New"
    }
  },
  "get_customer_kyc_record": {
    "description": "Retrieves the Know Your Customer (KYC) profile for a given entity, including Ultimate Beneficial Owner (UBO) details and the stated business nature/expected activity.",
    "parameters": {
      "type": "object",
      "properties": {
        "entity_name": {
          "type": "string",
          "description": "The name of the customer entity to query."
        }
      },
      "required": [
        "entity_name"
      ]
    },
    "example_output": {
      "ubo_details": "Jane Smith (60%), Mark Clean (40%)",
      "business_profile": "Commercial cleaning services; expected monthly cash volume $5,000-$8,000 via local branches.",
      "risk_rating": "Medium"
    }
  },
  "get_transaction_data": {
    "description": "Fetches detailed data for a list of transaction IDs, including amounts, dates, transaction types, and locations.",
    "parameters": {
      "type": "object",
      "properties": {
        "transaction_ids": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "The list of transaction IDs to investigate."
        }
      },
      "required": [
        "transaction_ids"
      ]
    },
    "example_output": {
      "transactions": [
        {
          "id": "TXN_001",
          "amount": 2900,
          "type": "Cash Deposit",
          "date": "2025-02-10",
          "location": "Downtown Branch"
        }
      ]
    }
  },
  "update_case_narrative": {
    "description": "Saves the investigative narrative and specific SAR metadata (amount and typology) into the alert system record.",
    "parameters": {
      "type": "object",
      "properties": {
        "alert_id": {
          "type": "string",
          "description": "The unique identifier for the AML alert."
        },
        "narrative_text": {
          "type": "string",
          "description": "The full SAR narrative following FinCEN 5 Ws standards, including UBO details and the 'Why' statement."
        },
        "total_sar_amount": {
          "type": "number",
          "description": "The calculated total suspicious amount."
        },
        "suspicious_typology": {
          "type": "string",
          "enum": [
            "Structuring",
            "Funnel Account"
          ],
          "description": "The identified suspicious activity pattern."
        }
      },
      "required": [
        "alert_id",
        "narrative_text",
        "total_sar_amount",
        "suspicious_typology"
      ]
    },
    "example_output": {
      "update_status": "Success"
    }
  },
  "transition_workflow_status": {
    "description": "Moves the alert to a new stage in the investigation lifecycle.",
    "parameters": {
      "type": "object",
      "properties": {
        "alert_id": {
          "type": "string",
          "description": "The unique identifier for the AML alert."
        },
        "new_status": {
          "type": "string",
          "description": "The target status (e.g., 'Pending_Approval')."
        }
      },
      "required": [
        "alert_id",
        "new_status"
      ]
    },
    "example_output": {
      "current_status": "Pending_Approval"
    }
  }
}
